import math

def lexComp(a, b):
    if a[0] != b[0]:
        return -1 if a[0] < b[0] else 1
    if a[1] != b[1]:
        return -1 if a[1] < b[1] else 1
    return 0

def turn(a, b, c):
    return (b[0] - a[0]) * (c[1] - b[1]) - (b[1] - a[1]) * (c[0] - b[0])

def dist2(a, b):
    return (a[0] - b[0]) ** 2 + (a[1] - b[1]) ** 2

def solve(n):
    a = [list(map(int, input())) for _ in range(n)]
    points = []
    for i in range(n):
        for j in range(n):
            if a[i][j] == 1:
                curPoints = []
                for dx in range(0, 2):
                    for dy in range(0, 2):
                        ok = True
                        for ddx in range(0, 2):
                            for ddy in range(0, 2):
                                x, y = i - 1 + dx + ddx, j - 1 + dy + ddy
                                if 0 <= x < n and 0 <= y < n and a[x][y] == 0:
                                    ok = False
                        if ok:
                            curPoints.append((i + dx, j + dy))
                points.append(curPoints[0])
    points = list(set(points))
    for i in range(1, len(points)):
        if lexComp(points[0], points[i]) > 0:
            points[0], points[i] = points[i], points[0]
    points[1:] = sorted(points[1:], key=lambda p: (math.atan2(p[1] - points[0][1], p[0] - points[0][0]), dist2(p, points[0])))
    hull = []
    for p in points:
        while len(hull) >= 2 and turn(hull[-2], hull[-1], p) <= 0:
            hull.pop()
        hull.append(p)
    hull = [(p[1], n - p[0]) for p in hull]
    hull = hull[::-1]
    start = 0
    for i in range(1, len(hull)):
        if lexComp(hull[i], hull[start]) < 0:
            start = i
    newHull = hull[start:]
    newHull.extend(hull[:start])
    hull = newHull
    print(len(hull))
    for p in hull:
        print(p[0], p[1])

while True:
    n = int(input())
    if n == 0:
        break
    solve(n)
```

【第一步：题意深度解读】
这道题的核心目标是让数组中的字符串行之间保持字典序非递减（即上一行 <= 下一行）。我们可以通过删除某些列来实现这一点。题目要求的是最少删除多少列。

潜在约束与关键点：
1. 删除是列级别的：一旦决定删除第 i 列，所有行的第 i 个字符都会消失。
2. 字典序判定：比较两个字符串时，从左到右找到第一个不同的字符，字符小的字符串更小。如果前面字符都相同，则短的更小（本题长度始终相同）。
3. 贪心策略暗示：为了让删除次数最少，我们应该尽可能保留列。从左到右遍历列，如果保留当前列不会破坏已有的排序关系，我们就保留；否则必须删除。

【第二步：核心逻辑推导】
我们需要维护一个状态，记录哪些行之间目前的字典序关系是“相等”的。只有对于目前“相等”的行对，当前列的字符大小关系才重要。

1. 初始化：最初，所有行都被视为一个整体区间 [0, N-1]，意味着它们目前看来都是“相等”的。
2. 遍历每一列：
   - 检查当前列在所有“相等区间”内是否是非递减的。
   - 如果某区间内当前列字符乱序（例如上一行字符 > 下一行字符），则这一列必须删除，否则无法保证最终有序。
   - 如果当前列在所有区间内都有序，我们可以保留这一列。此时，原本“相等”的行可能会因为当前列字符不同而变得“不等”。我们需要更新区间，将字符相同的行划分为新的子区间。
3. 终止条件：当所有行都被划分为长度为 1 的区间（即所有行关系已确定），或者所有列遍历完毕。

