    def maxProduct(self, nums):
        def prod(nums):
            prod_val = 1
            for i in nums:
                prod_val *= i
            return prod_val
        def listsplit(ls1, index):
            result = []
            st = -1
            for i in index:
                if i == 0:
                    st = i
                else:
                    result.append(ls1[st+1:i])
                    st = i
            if st < len(ls1)-1:
                result.append(ls1[st+1:])
            return result
